<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1"><?=e($job['job_number'])?></h1><p class="text-muted mb-0"><?=e($job['display_name'])?> · <?=e($job['service_summary'])?></p></div><span class="badge text-bg-primary fs-6"><?=e($job['status'])?></span></div><div class="row g-4"><div class="col-lg-7"><div class="card card-body mb-4"><h2 class="h5">Work order</h2><dl class="row mb-0"><dt class="col-sm-4">Address</dt><dd class="col-sm-8"><?=e($job['full_address'])?></dd><dt class="col-sm-4">Customer</dt><dd class="col-sm-8"><?=e($job['phone'])?><br><?=e($job['email'])?></dd><dt class="col-sm-4">Crew</dt><dd class="col-sm-8"><?=e($job['crew_name']?:'Unassigned')?></dd><dt class="col-sm-4">Technician</dt><dd class="col-sm-8"><?=e($job['technician']?:'Unassigned')?></dd><dt class="col-sm-4">Notes</dt><dd class="col-sm-8"><?=nl2br(e($job['notes']))?></dd></dl></div><div class="card card-body mb-4"><div class="d-flex justify-content-between"><h2 class="h5">Field checklist</h2><?php if(!$checklist):?><form method="post" action="/portal/jobs/<?=$job['id']?>/checklist/seed"><?=csrf_field()?><button class="btn btn-sm btn-outline-primary">Prepare Checklist</button></form><?php endif?></div><?php if($checklist):?><form method="post" action="/portal/jobs/<?=$job['id']?>/checklist"><?=csrf_field()?><?php foreach($checklist as $i):?><div class="form-check py-2 border-bottom"><input class="form-check-input" type="checkbox" name="items[]" value="<?=$i['id']?>" id="ci<?=$i['id']?>" <?=checked((bool)$i['completed'])?>><label class="form-check-label" for="ci<?=$i['id']?>"><?=e($i['label'])?></label></div><?php endforeach?><button class="btn btn-primary mt-3">Save Checklist</button></form><?php else:?><p class="text-muted mb-0">No checklist has been prepared for this job.</p><?php endif?></div><div class="card card-body"><h2 class="h5">Job Photos</h2><form method="post" action="/portal/jobs/<?=$job['id']?>/photos" enctype="multipart/form-data" class="row g-2 mb-3"><?=csrf_field()?><div class="col-md-3"><select class="form-select" name="photo_type"><option>before</option><option>during</option><option>after</option><option>damage</option><option>other</option></select></div><div class="col-md-5"><input class="form-control" type="file" name="photo" accept="image/jpeg,image/png,image/webp" required></div><div class="col-md-4"><button class="btn btn-outline-primary w-100">Upload Photo</button></div></form><div class="row g-2"><?php foreach($photos as $p):?><div class="col-6 col-md-4"><div class="border rounded p-2"><img class="img-fluid rounded" src="/uploads/<?=e($p['storage_path'])?>" alt="Job photo"><small class="d-block mt-1"><?=e($p['photo_type'])?> · <?=e($p['uploader'])?></small></div></div><?php endforeach?></div></div></div><div class="col-lg-5"><div class="card card-body mb-4"><h2 class="h5">Field status</h2><form method="post" action="/portal/jobs/<?=$job['id']?>/status" class="d-grid gap-2"><?=csrf_field()?><?php foreach(['scheduled'=>'Scheduled','in_progress'=>'Start Job','completed'=>'Complete Job','cancelled'=>'Cancel'] as $value=>$label):?><button name="status" value="<?=$value?>" class="btn btn-<?=$value==='completed'?'success':($value==='cancelled'?'danger':'outline-primary')?>"><?=$label?></button><?php endforeach?></form></div><?php if(\App\Core\Auth::can('owner','office','crew_leader')):?><div class="card card-body"><h2 class="h5">Schedule</h2><form method="post" action="/portal/jobs/<?=$job['id']?>/schedule"><?=csrf_field()?><div class="mb-3"><label class="form-label">Start</label><input required type="datetime-local" name="scheduled_start" class="form-control" value="<?=e($job['scheduled_start']?date('Y-m-d\TH:i',strtotime($job['scheduled_start'])):'')?>"></div><div class="mb-3"><label class="form-label">End</label><input required type="datetime-local" name="scheduled_end" class="form-control" value="<?=e($job['scheduled_end']?date('Y-m-d\TH:i',strtotime($job['scheduled_end'])):'')?>"></div><div class="mb-3"><label class="form-label">Assigned crew</label><select name="crew_id" class="form-select"><option value="">No crew</option><?php foreach($crews as $crew):?><option value="<?=$crew['id']?>" <?=selected($job['crew_id'],$crew['id'])?>><?=e($crew['name'])?><?= $crew['leader_name'] ? ' · '.e($crew['leader_name']) : '' ?></option><?php endforeach?></select><div class="form-text">Selecting a crew applies its default leader and vehicle when those fields are blank.</div></div><div class="mb-3"><label class="form-label">Assigned technician</label><select name="assigned_user_id" class="form-select"><option value="">Unassigned</option><?php foreach($users as $u):?><option value="<?=$u['id']?>" <?=selected($job['assigned_user_id'],$u['id'])?>><?=e($u['name'])?></option><?php endforeach?></select></div><div class="mb-3"><label class="form-label">Assigned vehicle</label><select name="assigned_vehicle_id" class="form-select"><option value="">No vehicle</option><?php foreach($vehicles as $v):?><option value="<?=$v['id']?>" <?=selected($job['assigned_vehicle_id'],$v['id'])?>><?=e($v['unit_number'])?></option><?php endforeach?></select></div><div class="form-check mb-3"><input class="form-check-input" type="checkbox" name="override_conflicts" value="1" id="overrideConflicts"><label class="form-check-label" for="overrideConflicts">Override crew availability or overlap warnings</label></div><button class="btn btn-primary w-100">Save & Sync to Outlook</button></form></div><?php endif?></div></div>

