<script>document.getElementById('checkInForm')?.addEventListener('submit',function(e){if(!navigator.geolocation)return;navigator.geolocation.getCurrentPosition(function(p){document.getElementById('checkLat').value=p.coords.latitude;document.getElementById('checkLng').value=p.coords.longitude;document.getElementById('checkAccuracy').value=p.coords.accuracy;},function(){});});</script>

<div class="card card-body mt-4"><h2 class="h5">Materials Used</h2><form method="post" action="/portal/jobs/<?=$job['id']?>/inventory" class="row g-2 mb-3"><?=csrf_field()?><div class="col-md-7"><select class="form-select" name="inventory_item_id" required><option value="">Choose inventory item</option><?php foreach($inventory as $i):?><option value="<?=$i['id']?>"><?=e($i['name'])?> (<?=e($i['quantity'].' '.$i['unit'])?> available)</option><?php endforeach?></select></div><div class="col-md-2"><input type="number" step=".01" min=".01" name="quantity" class="form-control" placeholder="Qty" required></div><div class="col-md-3"><button class="btn btn-outline-primary w-100">Record Usage</button></div></form><?php if($usage):?><table class="table table-sm"><thead><tr><th>Item</th><th>Quantity</th><th>Cost</th></tr></thead><tbody><?php foreach($usage as $u):?><tr><td><?=e($u['name'])?></td><td><?=e($u['quantity'].' '.$u['unit'])?></td><td><?=money((float)$u['quantity']*(float)$u['unit_cost'])?></td></tr><?php endforeach?></tbody></table><?php endif?></div>
<script>
(()=>{const c=document.getElementById('signaturePad');if(!c)return;const ctx=c.getContext('2d');let drawing=false;function resize(){const r=c.getBoundingClientRect();c.width=r.width*devicePixelRatio;c.height=r.height*devicePixelRatio;ctx.scale(devicePixelRatio,devicePixelRatio);ctx.lineWidth=2;ctx.lineCap='round'}resize();const pos=e=>{const r=c.getBoundingClientRect(),p=e.touches?e.touches[0]:e;return [p.clientX-r.left,p.clientY-r.top]};c.addEventListener('pointerdown',e=>{drawing=true;ctx.beginPath();ctx.moveTo(...pos(e))});c.addEventListener('pointermove',e=>{if(!drawing)return;ctx.lineTo(...pos(e));ctx.stroke()});window.addEventListener('pointerup',()=>drawing=false);document.getElementById('clearSignature')?.addEventListener('click',()=>ctx.clearRect(0,0,c.width,c.height));document.getElementById('signatureForm')?.addEventListener('submit',()=>document.getElementById('signatureData').value=c.toDataURL('image/png'));})();
</script>
<div class="row g-4 mt-1"><div class="col-lg-6"><div class="card card-body h-100"><h2 class="h5">Job Inspections</h2><form method="post" action="/portal/jobs/<?=$job['id']?>/inspections/start" class="d-flex gap-2 mb-3"><?=csrf_field()?><select name="inspection_template_id" class="form-select" required><option value="">Choose template</option><?php foreach($inspectionTemplates as $t):?><option value="<?=$t['id']?>"><?=e($t['name'])?></option><?php endforeach?></select><button class="btn btn-outline-primary">Start</button></form><?php if(!$inspections):?><p class="text-muted mb-0">No inspections yet.</p><?php else:?><div class="list-group"><?php foreach($inspections as $i):?><a class="list-group-item list-group-item-action d-flex justify-content-between" href="/portal/inspections/<?=$i['id']?>"><span><?=e($i['template_name'])?><small class="d-block text-muted"><?=e($i['created_at'])?></small></span><span class="badge text-bg-<?=$i['status']==='completed'?'success':'secondary'?>"><?=e($i['status'])?></span></a><?php endforeach?></div><?php endif?></div></div><div class="col-lg-6"><div class="card card-body h-100"><h2 class="h5">Additional Job Information</h2><?php if(empty($customFields)):?><p class="text-muted">No custom job fields are configured.</p><?php else:?><form method="post" action="/portal/jobs/<?=$job['id']?>/schedule" class="row g-3"><?=csrf_field()?><input type="hidden" name="scheduled_start" value="<?=e($job['scheduled_start'])?>"><input type="hidden" name="scheduled_end" value="<?=e($job['scheduled_end'])?>"><input type="hidden" name="assigned_user_id" value="<?=e($job['assigned_user_id'])?>"><input type="hidden" name="assigned_vehicle_id" value="<?=e($job['assigned_vehicle_id'])?>"><?php include dirname(__DIR__,2).'/partials/custom-fields.php';?><div class="col-12"><button class="btn btn-outline-primary">Save Additional Information</button></div></form><?php endif?></div></div></div>

<div class="row g-4 mt-1"><div class="col-lg-6"><div class="card card-body"><h2 class="h5">Suggested Crews</h2><?php foreach($crewSuggestions as $suggestion):?><div class="border rounded p-3 mb-2"><div class="d-flex justify-content-between"><strong><?=e($suggestion['crew']['name'])?></strong><span class="badge text-bg-<?=$suggestion['score']>=70?'success':($suggestion['score']>=40?'warning':'danger')?>"><?=$suggestion['score']?> score</span></div><ul class="small text-muted mb-0 mt-2"><?php foreach($suggestion['reasons'] as $reason):?><li><?=e($reason)?></li><?php endforeach?></ul></div><?php endforeach?></div></div><div class="col-lg-6"><div class="card card-body"><h2 class="h5">Assignment History</h2><?php if(!$assignmentHistory):?><p class="text-muted mb-0">No crew assignments recorded yet.</p><?php else:?><div class="list-group list-group-flush"><?php foreach($assignmentHistory as $h):?><div class="list-group-item px-0"><strong><?=e($h['crew_name']?:'No crew')?></strong><span class="text-muted"> · <?=e($h['technician_name']?:'No technician')?> · <?=e($h['unit_number']?:'No vehicle')?></span><small class="d-block text-muted"><?=e($h['created_at'])?> by <?=e($h['assigned_by_name']?:'System')?></small></div><?php endforeach?></div><?php endif?></div></div></div>